#include<bits/stdc++.h>
using namespace std;
priority_queue<int,vector<int>,greater<int>> q;
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        int op;
        cin>>op;
        if(op==1){
            int x;
            cin>>x;
            q.push(x);
        }else if(op==2){
            cout<<q.top()<<"\n";
        }else{
            q.pop();
        }
    }
    return 0;
}
